from typing import Any, Literal, Optional
from leann import LeannBuilder
from leann.api import LeannSearcher, SearchResult
from pathlib import Path


def build_multiple_indexes(
    index_configs: list[dict[str, Any]], base_dir: str
) -> dict[str, str]:
    if not index_configs:
        raise ValueError("index_configs cannot be empty")

    successful_indexes = {}
    for config in index_configs:
        errors = []
        if "index_name" not in config:
            errors.append(f"Config {config} is missing 'index_name'")
        if "documents" not in config:
            errors.append(f"Config {config} is missing 'documents'")
        if "documents" in config and not isinstance(config["documents"], list):
            errors.append(f"'documents' in config {config} is not a list")
        if errors:
            raise ValueError("\n".join(errors))

        index_name = config["index_name"]
        documents = config["documents"]
        backend_name = config.get("backend_name", "hnsw")
        index_path = Path(base_dir) / f"{index_name}.leann"
        index_path.parent.mkdir(parents=True, exist_ok=True)

        try:
            builder = LeannBuilder(backend_module_name=backend_name)
            builder.build_index(documents, index_path=str(index_path))
            successful_indexes[index_name] = str(index_path)
        except Exception as e:
            print(f"Warning: Could not build index {index_name}: {e}")

    return successful_indexes


def unified_search_across_indexes(
    index_paths: dict[str, str],
    query: str,
    top_k_per_index: int = 3,
    global_top_k: int = 0,
) -> list[SearchResult]:
    merged_results: list[SearchResult] = []
    seen_texts = set()

    for index_name, index_path in index_paths.items():
        try:
            searcher = LeannSearcher(index_path=index_path)
            results = searcher.search(query, top_k=top_k_per_index)
            for result in results:
                text = result.text
                if text not in seen_texts:
                    seen_texts.add(text)
                    merged_results.append(result)
        except Exception as e:
            print(f"Warning: Could not search in index {index_name}: {e}")

    merged_results.sort(key=lambda x: x.score, reverse=True)

    if global_top_k > 0:
        merged_results = merged_results[:global_top_k]

    return merged_results

