from typing import List, Optional
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Optional[dict],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    if not filter_specs:
        return search_results.copy()

    engine = MetadataFilterEngine()
    filtered = []

    for result in search_results:
        meta = result.metadata
        # Convert filter_specs into a list of per-field filters
        filter_list = [{k: v} for k, v in filter_specs.items()]
        matches = []

        for field_filter in filter_list:
            try:
                if engine.evaluate(meta, field_filter):
                    matches.append(True)
                else:
                    matches.append(False)
            except:
                matches.append(False)

        if (filter_logic == "AND" and all(matches)) or (filter_logic == "OR" and any(matches)):
            filtered.append(result)

    return filtered

