import numpy as np
from leann.api import compute_embeddings
from functools import lru_cache

def compute_embeddings_with_config(
    texts: List[str],
    model_name: str = "facebook/contriever",
    mode: str = "sentence-transformers",
    embedding_options: Optional[dict[str, Any]] = None,
    use_cache: bool = False
) -> np.ndarray:
    if not texts:
        raise ValueError("texts cannot be empty")
    valid_modes = {"sentence-transformers", "mlx", "openai", "ollama"}
    if mode not in valid_modes:
        raise ValueError(f"mode must be one of {valid_modes}")

    if use_cache:
        # Create a cache key that includes all parameters affecting the embedding computation
        options_set = frozenset(embedding_options.items()) if embedding_options else None
        cache_key = (tuple(texts), model_name, mode, options_set)

        # Use cached result if available; otherwise compute and cache
        def compute_func(**kwargs) -> np.ndarray:
            return _cached_compute(cache_key, provider_options=None)

        result = _get_cached_result(cache_key, compute_func)
    else:
        provider_options = embedding_options
        result = compute_embeddings(
            chunks=texts,
            model_name=model_name,
            mode=mode,
            use_server=False,
            is_build=False,
            provider_options=provider_options
        )

    return np.asarray(result)

# Internal cached computation helper
_cached_compute_memo: dict[tuple, np.ndarray] = {}

def _get_cached_result(key: tuple, compute_func) -> np.ndarray:
    if key in _cached_compute_memo:
        return _cached_compute_memo[key]
    result = compute_func()
    _cached_compute_memo[key] = result
    return result

def _cached_compute(cache_key: tuple, provider_options: Optional[dict[str, Any]] = None) -> np.ndarray:
    texts_tuple, model_name, mode, options_set = cache_key
    texts_list = list(texts_tuple)
    embedding_opts = dict(options_set) if options_set else provider_options
    return compute_embeddings(
        chunks=texts_list,
        model_name=model_name,
        mode=mode,
        use_server=False,
        is_build=False,
        provider_options=embedding_opts
    )

