def get_index_statistics(index_path: str) -> dict[str, Any]:
    pm = PassageManager(index_path)
    passage_sources = pm.meta.get("passage_sources", [])
    total_passages = sum(len(source) for source in passage_sources)

    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for source in passage_sources:
        for passage in source:
            meta = passage.get("metadata", {})
            for field, value in meta.items():
                metadata_fields.add(field)
                field_value_counts[field][value] += 1

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(metadata_fields),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()},
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    pm = PassageManager(index_path)
    passage_sources = pm.meta.get("passage_sources", [])
    total_passages = sum(len(source) for source in passage_sources)

    covered = 0
    field_counts = defaultdict(int)
    missing_fields = set(required_fields)

    for source in passage_sources:
        for passage in source:
            meta = passage.get("metadata", {})
            present_fields = set(meta.keys())
            if missing_fields.issubset(present_fields):
                covered += 1
            for field in required_fields:
                if field in present_fields:
                    field_counts[field] += 1
                    missing_fields.discard(field)

    coverage_percentage = (covered / total_passages) * 100 if total_passages > 0 else 0.0
    field_coverage = {field: (count / total_passages) * 100 for field, count in field_counts.items()}

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": field_coverage,
        "missing_fields": sorted(missing_fields),
    }

