def search_with_result_expansion(
    index_path: str,
    query: str,
    expand_by_field: str,
    expansion_count: int = 1,
    top_k: int = 10,
) -> list[SearchResult]:
    if expansion_count < 0:
        raise ValueError("expansion_count must be non-negative")
    try:
        searcher = LeannSearcher(index_path)
    except FileNotFoundError:
        raise FileNotFoundError(f"Index file not found: {index_path}")
    initial_results = searcher.search(query, top_k=top_k)
    field_values = []
    for result in initial_results:
        value = result.metadata.get(expand_by_field)
        if value is not None:
            field_values.append(value)
    unique_values = set(field_values)
    expanded = []
    for value in unique_values:
        field_query = f"{expand_by_field}:{value}"
        try:
            exp_res = searcher.search(field_query, top_k=expansion_count)
            expanded.extend(exp_res)
        except Exception:
            pass  # Skip if expansion search fails
    return initial_results + expanded

